sql:
SELECT ap.program_type, AVG(ap.fees) AS average_fees
FROM academic_programs ap
GROUP BY ap.program_type;

SELECT COUNT(*) AS total_applications
FROM student_applications
WHERE status = 'allocated';

SELECT COUNT(*) AS total_applications
FROM student_applications
WHERE program_id = 101 AND round_id = 1;

SELECT available_seats
FROM admission_round_details
WHERE program_id = 1 AND round_id = 1;

external_knowledge:
- "flourishing flowers" refers to academic programs with the highest number of open seats;
- "open spots for new seeds" represents available seats for new students;
- "top five blooms" refers to the top five programs with the most available seats;
- "blossoming spaces" are the available seats in each program;
- "total number of blossoms" represents the grand total of available seats across all top five programs.

sql:
SELECT institute_name, established_year
FROM institutes
ORDER BY established_year DESC;
